'use strict';

/**
 * Flatten an array of nested arrays into a single flat array.
 * This is a dependency used by Express.js for route normalization and handling.
 *
 * @param {Array} array - The array to flatten
 * @param {Boolean} [shallow=false] - If true, only flatten one level deep
 * @param {Array} [result=[]] - The result array (used for recursion)
 * @returns {Array} A flattened version of the input array
 * @public
 */
function flatten(array, shallow, result) {
  // If no array is provided, return an empty array
  if (array == null) {
    return [];
  }

  // Initialize the result array if not provided
  result = result || [];
  
  // Handle shallow flattening
  shallow = shallow || false;

  // Iterate through each item in the array
  var i = 0;
  var len = array.length;

  for (; i < len; i++) {
    var value = array[i];

    // If the value is an array and we're not doing shallow flattening
    // or if we are doing shallow flattening and we're at the first level
    if (Array.isArray(value)) {
      // If we're doing a shallow flatten, just concat the array
      if (shallow) {
        var j = 0;
        var vLen = value.length;

        for (; j < vLen; j++) {
          result.push(value[j]);
        }
      } else {
        // Otherwise, recursively flatten
        flatten(value, shallow, result);
      }
    } else {
      // If the value is not an array, just add it to the result
      result.push(value);
    }
  }

  return result;
}

/**
 * Flatten an array of nested arrays into a single flat array.
 * This is a simpler version that always does a deep flatten.
 *
 * @param {Array} array - The array to flatten
 * @returns {Array} A flattened version of the input array
 * @public
 */
function flattenDeep(array) {
  return flatten(array, false);
}

/**
 * Flatten an array of nested arrays one level deep.
 *
 * @param {Array} array - The array to flatten
 * @returns {Array} An array flattened one level deep
 * @public
 */
function flattenShallow(array) {
  return flatten(array, true);
}

// Export the functions
module.exports = flatten;
module.exports.flatten = flatten;
module.exports.flattenDeep = flattenDeep;
module.exports.flattenShallow = flattenShallow;